    logout_user()
    flash('Você foi desconectado com sucesso.', 'info')
    return redirect(url_for('login'))


# Rotas de integração com Fluig
@app.route('/nfe/integrar-fluig/<int:nfe_id>')
@login_required_hybrid
def integrar_fluig(nfe_id):
    """Integrar NFE com o sistema Fluig"""
    nfe_record = NFERecord.query.get_or_404(nfe_id)

    # Verificar se o usuário tem permissão para acessar este arquivo
    if nfe_record.user_id != current_user.id:
        return jsonify({'success': False, 'message': 'Acesso negado!'})

    # Verificar se já foi integrado
    if nfe_record.fluig_process_id:
        return jsonify({
            'success': False, 
            'message': f'NFE já integrada ao Fluig! Processo ID: {nfe_record.fluig_process_id}'
        })

    # Obter integração Fluig para o usuário
    fluig_integration = get_fluig_integration_for_user(current_user.id)

    if not fluig_integration:
        return jsonify({
            'success': False, 
            'message': 'Configuração do Fluig não encontrada. Configure suas credenciais nas configurações do sistema.'
        })

    # Marcar como processando
    nfe_record.fluig_integration_status = 'PROCESSANDO'
    db.session.commit()

    # Executar integração em thread separada para evitar timeout
    import threading
    from app import app

    def execute_integration():
        with app.app_context():  # Criar contexto da aplicação Flask
            try:
                # Buscar o registro NFE e o arquivo PDF original
                nfe_record = NFERecord.query.get(nfe_id)
                if not nfe_record:
                    raise ValueError(f"Registro NFE não encontrado: {nfe_id}")

                # Obter o caminho do arquivo PDF original
                uploaded_file = UploadedFile.query.get(nfe_record.uploaded_file_id)
                if not uploaded_file or not uploaded_file.file_path:
                    raise ValueError(f"Arquivo PDF não encontrado para NFE {nfe_record.numero_nf}")

                # Usar o método completo que inclui upload do PDF
                result = fluig_integration.create_workflow_launch(nfe_record, uploaded_file.file_path)
                logging.info(f"🎯 Resultado da integração COM ANEXO: {result}")

                # Se a integração foi bem-sucedida, salvar no banco
                if result.get('success'):
                    nfe_record.fluig_process_id = str(result.get('process_id'))
                    nfe_record.fluig_integration_status = 'INTEGRADO'
                    from datetime import datetime
                    nfe_record.fluig_integration_date = datetime.now()
                    nfe_record.fluig_integration_data = str(result)
                    db.session.commit()
                    logging.info(f"✅ Process ID {result.get('process_id')} salvo no banco com sucesso!")
                else:
                    # Se houve falha, marcar como erro
                    nfe_record.fluig_integration_status = 'ERRO'
                    nfe_record.fluig_integration_data = str(result)
                    db.session.commit()
                    logging.error(f"❌ Integração falhou: {result.get('message')}")

            except Exception as e:
                logging.error(f"❌ Erro na integração assíncrona: {str(e)}")
                # Marcar como erro no banco
                nfe_record = NFERecord.query.get(nfe_id)
                if nfe_record:
                    nfe_record.fluig_integration_status = 'ERRO'
                    db.session.commit()

    # Iniciar thread em segundo plano
    thread = threading.Thread(target=execute_integration)
    thread.daemon = True
    thread.start()

    # Retornar resposta imediata
    return jsonify({
        'success': True,
        'message': 'Integração iniciada! Processo será executado em segundo plano. Aguarde alguns minutos e verifique o status.',
        'status': 'PROCESSANDO'
    })


@app.route('/nfe/status-fluig/<int:nfe_id>')
@login_required_hybrid
def status_fluig(nfe_id):
    """Verificar status da integração Fluig"""
    nfe_record = NFERecord.query.get_or_404(nfe_id)

    # Verificar se o usuário tem permissão para acessar este arquivo
    if nfe_record.user_id != current_user.id:
        return jsonify({'success': False, 'message': 'Acesso negado!'})

    status = nfe_record.fluig_integration_status or 'PENDENTE'

    if nfe_record.fluig_process_id:
        return jsonify({
            'success': True,
            'integrated': True,
            'status': 'INTEGRADO',
            'process_id': nfe_record.fluig_process_id,
            'document_id': nfe_record.fluig_document_id,
            'integration_date': nfe_record.fluig_integration_date.strftime('%d/%m/%Y %H:%M:%S') if nfe_record.fluig_integration_date else None
        })
    elif status == 'PROCESSANDO':
        return jsonify({
            'success': True,
            'integrated': False,
            'status': 'PROCESSANDO',
            'message': 'Integração em andamento... Aguarde alguns minutos.'
        })
    elif status == 'ERRO':
        return jsonify({
            'success': True,
            'integrated': False,
            'status': 'ERRO',
            'message': 'Erro na integração. Verifique os logs ou tente novamente.'
        })
    else:
        return jsonify({
            'success': True,
            'integrated': False,
            'status': 'PENDENTE',
            'message': 'NFE não integrada ao Fluig'
        })


